A: code("
import os, time, jwt
from dataclasses import dataclass

SECRET = os.environ['JWT_SECRET']
SIGN_ALGO = 'HS256'
VERIFY_ALGOS = ['HS256']
GRANDFATHER_CUTOVER = int(os.environ.get('JWT_CUTOVER_TS', str(int(time.time()))))
GRANDFATHER_WINDOW = 30 * 24 * 3600

@dataclass
class Token:
    sub: str
    exp: int
    role: str

def sign(sub, role, ttl=3600):
    now = int(time.time())
    payload = {'sub': sub, 'role': role, 'iat': now, 'exp': now + ttl}
    return jwt.encode(payload, SECRET, algorithm=SIGN_ALGO)

def verify(token):
    header = jwt.get_unverified_header(token)
    if header.get('alg') != 'HS256':
        raise ValueError('bad algo')
    payload = jwt.decode(
        token,
        SECRET,
        algorithms=VERIFY_ALGOS,
        options={'require': ['exp'], 'verify_exp': True},
    )
    iat = payload.get('iat')
    now = int(time.time())
    if iat is None:
        if now > GRANDFATHER_CUTOVER + GRANDFATHER_WINDOW:
            raise ValueError('legacy token past grandfather window')
    return Token(sub=payload['sub'], exp=payload['exp'], role=payload.get('role', 'user'))

def require_admin(token_str):
    t = verify(token_str)
    if t.role != 'admin':
        raise PermissionError('not admin')
    return t
